interface.definition:
a!localVariables(
  local!attachment: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1520799"(
    eventId: ri!eventID
  ).data,
  local!selectedDocument: null,
/*attachmant List*/
  if(
    a!defaultValue(value: ri!showWhen, default: true),
    if(
      a!isNullOrEmpty(local!attachment),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        label: "Empty Message",
        labelPosition: "COLLAPSED",
        value: #"SYSTEM_SYSRULES_richTextItem_v1"(
          text: #"urn:appian:translation-string:v1:37e0bad3-b656-433a-9744-11372606b48c"
        )
      ),
      {
        #"SYSTEM_SYSRULES_forEach"(
          items: local!attachment,
          expression: #"SYSTEM_SYSRULES_cardLayout"(
            showBorder: false,
            padding: "NONE",
            link: #"SYSTEM_SYSRULES_dynamicLink"(
              saveInto: a!save(local!selectedDocument,fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/2e5753c4-e094-4e27-b8af-32c9447ddcbf"])
            ),
            contents: #"SYSTEM_SYSRULES_sideBySideLayout"(
              items: {
                #"SYSTEM_SYSRULES_sideBySideItem"(
                  width: "MINIMIZE",
                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                    labelPosition: "COLLAPSED",
                    value: #"SYSTEM_SYSRULES_richTextIcon"(icon: #"2119728b-2f76-4641-a58a-299ab3c18926"(fileType: upper(fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/79c16d9b-9cce-4e0a-81bc-962f7bfc35e2"]))),
                  )
                ),
                #"SYSTEM_SYSRULES_sideBySideItem"(
                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                    labelPosition: "COLLAPSED",
                    value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/02925b99-1527-48bb-9fc8-406df81b2170"],
                      style: "UNDERLINE"
                    )
                  )
                ),
                #"SYSTEM_SYSRULES_sideBySideItem"(
                  showWhen: ri!deleteable = true,
                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                    align: "RIGHT",
                    labelPosition: "COLLAPSED",
                    value: #"SYSTEM_SYSRULES_richTextIcon"(
                      caption: #"urn:appian:translation-string:v1:0bfcc1ea-ecbf-4d6e-9558-4c44aec34025",
                      icon: if(
                        contains(ri!attachmentIdsToDelete,fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/0b9f9459-c913-4e8e-86e6-73dfaf78c84a"]),
                        "check-square-o",
                        "square-o"
                      ),
                      linkStyle: "STANDALONE",
                      link: #"SYSTEM_SYSRULES_dynamicLink"(
                        saveInto: a!save(
                          ri!attachmentIdsToDelete,
                          if(
                            contains(ri!attachmentIdsToDelete,fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/0b9f9459-c913-4e8e-86e6-73dfaf78c84a"]),
                            remove(ri!attachmentIdsToDelete,wherecontains(fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/0b9f9459-c913-4e8e-86e6-73dfaf78c84a"],local!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/0b9f9459-c913-4e8e-86e6-73dfaf78c84a"])),
                            append(ri!attachmentIdsToDelete,fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/0b9f9459-c913-4e8e-86e6-73dfaf78c84a"])
                          )
                        )
                      )
                    )
                  )
                )
              }
            )
          )
        ),
        /*attachment details*/
        #"SYSTEM_SYSRULES_sideBySideLayout"(
          showWhen: a!isNotNullOrEmpty(local!selectedDocument),
          marginBelow: "STANDARD",
          items: {
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_documentViewerField"(
                document: local!selectedDocument,
              )
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              width: "MINIMIZE",
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                label: "CLOSE DOC",
                labelPosition: "COLLAPSED",
                align: "RIGHT",
                value: #"SYSTEM_SYSRULES_richTextIcon"(
                  icon: "times",
                  size: "MEDIUM",
                  linkStyle: "STANDALONE",
                  link: #"SYSTEM_SYSRULES_dynamicLink"(
                    saveInto: a!save(local!selectedDocument,null)
                  )
                )
              )
            )
          }
        )
      }
    ),
    {}
  )
)
